+            assert_eq!(rf.doc_id, rs.doc_id);
+            assert_eq!(rf.doc_type, rs.doc_type);
+            // Scores should be very close (F16 precision loss is minimal)
+            assert!(
+                (rf.score - rs.score).abs() < 0.001,
+                "Scores differ: {} vs {}",
